void AfficherArborescence(string chemin, string prefixe = "")
{
    DirectoryInfo dir = new DirectoryInfo(chemin);
    foreach (var d in dir.GetDirectories())
    {
        Console.WriteLine($"{prefixe}┣━ {d.Name}");
        AfficherArborescence(d.FullName, prefixe + "┃  ");
    }
    foreach (var f in dir.GetFiles())
    {
        Console.WriteLine($"{prefixe}┣━ {f.Name}");
    }
}
